"use client";

import React, { useState, useMemo } from 'react';
import { 
  Search, Trophy, Home, List, Users, 
  ChevronRight, Crown, Activity, 
  ChevronLeft, Copy, Shield, X, Swords, Crosshair
} from 'lucide-react';
import playersData from '../data/players.json';

export default function McTierUltimate() {
  const [search, setSearch] = useState("");
  const [activeTab, setActiveTab] = useState("Overall");
  const [isExpanded, setIsExpanded] = useState(false);
  const [copied, setCopied] = useState(false);
  
  // NEW: State for the Stats GUI Modal
  const [selectedPlayer, setSelectedPlayer] = useState<any | null>(null);

  const handleCopy = () => {
    navigator.clipboard.writeText("play.nordenmc.com");
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const getTierStyles = (tier: string) => {
    if (tier?.includes('HT1')) return 'text-red-500 border-red-500/50 bg-red-500/10 shadow-[0_0_20px_rgba(239,68,68,0.3)]';
    if (tier?.includes('LT1')) return 'text-cyan-400 border-cyan-500/50 bg-cyan-500/10 shadow-[0_0_20px_rgba(6,182,212,0.3)]';
    if (tier?.includes('T2')) return 'text-purple-400 border-purple-500/40 bg-purple-500/10 shadow-[0_0_15px_rgba(168,85,247,0.2)]';
    return 'text-gray-400 border-white/10 bg-white/5';
  };

  // Fake power level generator for the UI based on Tier
  const getPowerLevel = (tier: string) => {
    if (tier?.includes('HT1')) return 98;
    if (tier?.includes('LT1')) return 85;
    if (tier?.includes('T2')) return 70;
    return 50;
  };

  const filteredPlayers = useMemo(() => {
    const data = Array.isArray(playersData) ? playersData : [];
    return data
      .filter((player: any) => {
        const matchesSearch = player.name?.toLowerCase().includes(search.toLowerCase());
        const matchesTab = activeTab === "Overall" || player.kit === activeTab;
        return matchesSearch && matchesTab;
      })
      .sort((a: any, b: any) => (a.rank || 0) - (b.rank || 0));
  }, [search, activeTab]);

  return (
    <div className="flex min-h-screen bg-[#050507] text-[#e1e1e3] font-sans overflow-x-hidden selection:bg-cyan-500/30 relative">
      
      {/* --- STATS GUI MODAL (NEW) --- */}
      {selectedPlayer && (
        <div 
          className="fixed inset-0 bg-black/80 backdrop-blur-sm z-[200] flex items-center justify-center p-4 animate-in fade-in duration-300"
          onClick={() => setSelectedPlayer(null)}
        >
          <div 
            className="bg-[#0a0a0d] border border-cyan-500/30 rounded-[2rem] w-full max-w-2xl overflow-hidden shadow-[0_0_50px_rgba(6,182,212,0.15)] animate-in zoom-in-95 duration-300"
            onClick={e => e.stopPropagation()} // Prevent clicking inside from closing modal
          >
            {/* Modal Header */}
            <div className="relative h-32 bg-gradient-to-r from-cyan-900/40 to-[#0a0a0d] border-b border-white/10 flex items-end p-8">
              <button 
                onClick={() => setSelectedPlayer(null)}
                className="absolute top-6 right-6 text-gray-400 hover:text-white hover:bg-white/10 p-2 rounded-full transition-all"
              >
                <X size={24} />
              </button>
              <div className="absolute -bottom-10 left-8">
                <img 
                  src={`https://mc-heads.net/avatar/${selectedPlayer.name}/150`} 
                  className="w-24 h-24 rounded-2xl border-4 border-[#0a0a0d] shadow-2xl bg-[#0f0f13]"
                  alt={selectedPlayer.name}
                />
              </div>
            </div>

            {/* Modal Body */}
            <div className="p-8 pt-14">
              <div className="flex justify-between items-start mb-8">
                <div>
                  <h2 className="text-3xl font-black italic tracking-tight flex items-center gap-3">
                    {selectedPlayer.name}
                    {selectedPlayer.rank <= 3 && <Crown size={24} className="text-yellow-500" />}
                  </h2>
                  <p className="text-cyan-500 font-bold tracking-widest uppercase text-sm mt-1 flex items-center gap-2">
                    <Crosshair size={14} /> Global Rank #{selectedPlayer.rank}
                  </p>
                </div>
                <div className={`px-8 py-3 rounded-xl border ${getTierStyles(selectedPlayer.tier)}`}>
                  <span className="text-3xl font-black italic">{selectedPlayer.tier}</span>
                </div>
              </div>

              {/* Stats Grid */}
              <div className="grid grid-cols-2 gap-4 mb-8">
                <div className="bg-white/5 border border-white/5 p-5 rounded-2xl">
                  <div className="text-gray-500 text-xs font-black uppercase tracking-widest mb-1 flex items-center gap-2">
                    <Activity size={12} className="text-cyan-500"/> Main Kit
                  </div>
                  <div className="text-2xl font-bold text-white">{selectedPlayer.kit || "Hybrid"}</div>
                </div>
                <div className="bg-white/5 border border-white/5 p-5 rounded-2xl">
                  <div className="text-gray-500 text-xs font-black uppercase tracking-widest mb-1 flex items-center gap-2">
                    <Swords size={12} className="text-red-500"/> Status
                  </div>
                  <div className="text-2xl font-bold text-green-400 flex items-center gap-2">
                    <div className="w-3 h-3 rounded-full bg-green-500 animate-pulse"></div> Online
                  </div>
                </div>
              </div>

              {/* Power Bar */}
              <div>
                <div className="flex justify-between text-xs font-black uppercase tracking-widest text-gray-500 mb-2">
                  <span>Combat Rating</span>
                  <span className="text-cyan-400">{getPowerLevel(selectedPlayer.tier)}%</span>
                </div>
                <div className="w-full h-3 bg-white/5 rounded-full overflow-hidden border border-white/5">
                  <div 
                    className="h-full bg-gradient-to-r from-cyan-600 to-cyan-400 shadow-[0_0_10px_#22d3ee]"
                    style={{ width: `${getPowerLevel(selectedPlayer.tier)}%` }}
                  ></div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* --- SIDEBAR --- */}
      <aside className={`hidden lg:flex flex-col py-8 border-r border-white/5 bg-[#08080a] sticky top-0 h-screen transition-all duration-500 ease-[cubic-bezier(0.4,0,0.2,1)] z-[100] shadow-[10px_0_30px_rgba(0,0,0,0.5)] ${isExpanded ? 'w-64 px-6' : 'w-20 items-center'}`}>
        <div onClick={() => setIsExpanded(!isExpanded)} className="mb-10 cursor-pointer text-cyan-500 bg-cyan-500/10 p-3 rounded-2xl border border-cyan-500/20 hover:scale-110 hover:shadow-[0_0_25px_rgba(6,182,212,0.4)] transition-all duration-300">
          {isExpanded ? <ChevronLeft size={28} /> : <Trophy size={28} />}
        </div>
        <nav className="flex flex-col gap-8 text-gray-500 w-full">
          {[{ icon: <Home size={24} />, label: "Dashboard" }, { icon: <List size={24} />, label: "Rankings", active: true }, { icon: <Users size={24} />, label: "Community" }].map((item, idx) => (
            <div key={idx} className={`flex items-center gap-4 cursor-pointer hover:text-cyan-400 transition-colors group ${isExpanded ? 'px-2' : 'justify-center'}`}>
              <div className={`transition-transform duration-300 group-hover:scale-110 ${item.active ? 'text-cyan-500' : ''}`}>{item.icon}</div>
              {isExpanded && <span className={`font-bold tracking-wide ${item.active ? 'text-white' : ''}`}>{item.label}</span>}
            </div>
          ))}
        </nav>
      </aside>

      <div className="flex-1 flex flex-col min-w-0">
        
        {/* --- TOP IP STATUS BAR --- */}
        <div className="bg-gradient-to-r from-cyan-500/5 via-cyan-500/10 to-cyan-500/5 border-b border-cyan-500/20 py-2.5 px-8 flex items-center justify-center gap-6 text-[10px] font-black uppercase tracking-[0.2em] text-cyan-400 shadow-[0_0_20px_rgba(6,182,212,0.05)]">
          <div className="flex items-center gap-2"><div className="w-2 h-2 rounded-full bg-cyan-400 animate-pulse shadow-[0_0_8px_#22d3ee]" /> Servers Online</div>
          <div className="w-px h-3 bg-cyan-500/30" />
          <div className="flex items-center gap-2 cursor-pointer hover:text-white transition-colors group" onClick={handleCopy}>
            <span className="group-hover:underline">{copied ? "IP COPIED TO CLIPBOARD!" : "IP: PLAY.NORDENMC.COM"}</span> <Copy size={12} className={copied ? "text-green-400" : ""} />
          </div>
        </div>

        {/* --- HEADER --- */}
        <header className="h-24 border-b border-white/5 bg-[#050507]/80 backdrop-blur-2xl sticky top-0 z-40 px-8 flex items-center justify-between">
          <h1 className="text-3xl font-black italic tracking-tighter text-white drop-shadow-[0_0_15px_rgba(255,255,255,0.1)] flex items-center gap-3">
            NORDEN<span className="text-cyan-500 drop-shadow-[0_0_15px_rgba(6,182,212,0.4)]">MC</span> 
            <span className="text-[10px] not-italic bg-white/5 border border-white/10 px-2 py-1 rounded-md text-gray-400">BETA</span>
          </h1>
          <div className="relative w-72 md:w-96 group">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 group-focus-within:text-cyan-400 transition-colors" size={18} />
            <input type="text" placeholder="Search contenders..." className="w-full bg-[#0a0a0d] border border-white/10 rounded-2xl py-3 pl-12 pr-4 outline-none focus:border-cyan-500/50 focus:shadow-[0_0_20px_rgba(6,182,212,0.15)] transition-all text-sm text-white" value={search} onChange={(e) => setSearch(e.target.value)} />
          </div>
        </header>

        <main className="p-6 md:p-10 max-w-7xl mx-auto w-full">
          
          {/* --- TOP 3 PODIUM CARDS --- */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
            {filteredPlayers.slice(0, 3).map((p, i) => (
              <div 
                key={p.name} 
                onClick={() => setSelectedPlayer(p)}
                className="relative overflow-hidden bg-gradient-to-br from-[#0f0f13] to-[#08080a] border border-white/5 p-6 rounded-[2rem] shadow-2xl hover:border-cyan-500/40 hover:shadow-[0_10px_40px_rgba(6,182,212,0.1)] transition-all duration-500 group hover:-translate-y-1 cursor-pointer"
              >
                <div className="absolute -right-6 -top-6 opacity-5 group-hover:opacity-10 group-hover:scale-110 transition-all duration-700">
                   <Trophy size={140} />
                </div>
                <div className="flex items-center gap-5 relative z-10">
                  <div className="relative">
                    <img src={`https://mc-heads.net/avatar/${p.name}/100`} className="w-16 h-16 rounded-2xl border-2 border-white/10 group-hover:border-cyan-500/50 transition-colors duration-500" alt="" />
                    <div className="absolute -bottom-1 -right-1 w-4 h-4 bg-green-500 border-4 border-[#08080a] rounded-full shadow-[0_0_10px_#22c55e]"></div>
                  </div>
                  <div>
                    <h3 className="font-black text-xl flex items-center gap-2 italic text-white group-hover:text-cyan-50 transition-colors">{p.name} <Crown size={18} className={i === 0 ? "text-yellow-500 drop-shadow-[0_0_8px_rgba(234,179,8,0.5)]" : "text-gray-500"} /></h3>
                    <p className="text-[10px] uppercase font-black tracking-widest text-cyan-500/70 mt-1">Global Rank #{p.rank}</p>
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* --- KIT FILTER TABS --- */}
          <div className="flex flex-wrap gap-3 mb-10 bg-[#0a0a0d] p-1.5 rounded-2xl w-fit border border-white/5 shadow-lg">
            {['Overall', 'Crystal', 'Sword', 'UHC', 'Axe'].map((tab) => (
              <button 
                key={tab} 
                onClick={() => setActiveTab(tab)}
                className={`px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all duration-300 ${
                  activeTab === tab 
                  ? 'bg-cyan-500 text-[#050507] shadow-[0_0_20px_rgba(6,182,212,0.4)] scale-105' 
                  : 'text-gray-500 hover:text-white hover:bg-white/5'
                }`}
              >
                {tab}
              </button>
            ))}
          </div>

          {/* --- MAIN PLAYER LIST --- */}
          <div className="bg-[#0a0a0d] border border-white/5 rounded-[2.5rem] overflow-hidden shadow-2xl relative backdrop-blur-sm">
            
            {/* List Header */}
            <div className="grid grid-cols-12 gap-4 p-6 bg-white/[0.02] border-b border-white/5 text-[10px] text-gray-500 font-black uppercase tracking-[0.3em]">
              <div className="col-span-1 pl-4">Pos</div>
              <div className="col-span-7">Contender Profile</div>
              <div className="col-span-4 text-right pr-8">Combat Rating</div>
            </div>

            {/* List Body */}
            <div className="divide-y divide-white/[0.02]">
              {filteredPlayers.map((player: any) => (
                <div 
                  key={player.name} 
                  onClick={() => setSelectedPlayer(player)}
                  className="grid grid-cols-12 gap-4 p-5 md:p-6 items-center hover:bg-[#0f0f13] transition-all duration-300 group cursor-pointer"
                >
                  
                  {/* Position */}
                  <div className="col-span-1 text-3xl font-black italic text-gray-800/50 group-hover:text-cyan-500/30 transition-colors pl-4">
                    {player.rank.toString().padStart(2, '0')}
                  </div>
                  
                  {/* Player Info */}
                  <div className="col-span-7 flex items-center gap-5">
                    <div className="relative">
                      <img 
                        src={`https://mc-heads.net/avatar/${player.name}/100`} 
                        className="w-14 h-14 rounded-xl border border-white/10 group-hover:border-cyan-500/40 transition-all duration-500 group-hover:scale-110 shadow-lg"
                        alt={player.name}
                      />
                      <div className="absolute -bottom-1 -right-1 w-3.5 h-3.5 bg-green-500 border-[3px] border-[#0a0a0d] rounded-full"></div>
                    </div>
                    <div>
                      <div className="flex items-center gap-3 font-black text-xl tracking-tight text-white/90 group-hover:text-white transition-colors">
                         {player.name}
                         {player.rank <= 3 && <Shield size={14} className="text-cyan-500" />}
                      </div>
                      <div className="flex items-center gap-2 text-[10px] text-gray-500 font-bold uppercase mt-1 tracking-wider">
                        <Activity size={12} className="text-cyan-500" />
                        {player.kit || "Hybrid"} Master
                      </div>
                    </div>
                  </div>

                  {/* Rating / Tier */}
                  <div className="col-span-4 flex justify-end items-center gap-6 pr-6">
                    <div className={`border px-6 py-2 rounded-xl transition-all duration-500 group-hover:scale-110 ${getTierStyles(player.tier)}`}>
                      <span className="text-xl font-black italic tracking-tighter">
                        {player.tier}
                      </span>
                    </div>
                    <div className="w-10 h-10 rounded-full border border-white/5 flex items-center justify-center text-gray-600 group-hover:bg-cyan-500/10 group-hover:text-cyan-400 group-hover:border-cyan-500/30 transition-all duration-300">
                       <ChevronRight size={20} className="group-hover:translate-x-1 transition-transform" />
                    </div>
                  </div>

                </div>
              ))}
            </div>
          </div>
          
        </main>
      </div>
    </div>
  );
}